   181→func TestDebounce(t *testing.T) {
   182→	// This test tests the timeout and debouncing of config updates
   183→	// If it is flaking, DebounceAfter may need to be increased, or the code refactored to mock time.
   184→	// For now, this seems to work well
   185→	opts := DebounceOptions{
   186→		DebounceAfter:     time.Millisecond * 50,
   187→		debounceMax:       time.Millisecond * 100,
   188→		enableEDSDebounce: false,
   189→	}
   190→
   191→	tests := []struct {
   192→		name string
   193→		test func(updateCh chan *model.PushRequest, expect func(partial, full int32))
   194→	}{
   195→		{
   196→			name: "Should not debounce partial pushes",
   197→			test: func(updateCh chan *model.PushRequest, expect func(partial, full int32)) {
   198→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   199→				expect(1, 0)
   200→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   201→				expect(2, 0)
   202→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   203→				expect(3, 0)
   204→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   205→				expect(4, 0)
   206→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   207→				expect(5, 0)
   208→			},
   209→		},
   210→		{
   211→			name: "Should debounce full pushes",
   212→			test: func(updateCh chan *model.PushRequest, expect func(partial, full int32)) {
   213→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   214→				expect(0, 0)
   215→			},
   216→		},
   217→		{
   218→			name: "Should send full updates in batches",
   219→			test: func(updateCh chan *model.PushRequest, expect func(partial, full int32)) {
   220→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   221→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   222→				expect(0, 1)
   223→			},
   224→		},
   225→		{
   226→			name: "Should send full updates in batches, partial updates immediately",
   227→			test: func(updateCh chan *model.PushRequest, expect func(partial, full int32)) {
   228→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   229→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   230→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   231→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   232→				expect(2, 1)
   233→				updateCh <- &model.PushRequest{Full: false, Forced: true}
   234→				expect(3, 1)
   235→			},
   236→		},
   237→		{
   238→			name: "Should force a push after DebounceMax",
   239→			test: func(updateCh chan *model.PushRequest, expect func(partial, full int32)) {
   240→				// Send many requests within debounce window
   241→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   242→				time.Sleep(opts.DebounceAfter / 2)
   243→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   244→				time.Sleep(opts.DebounceAfter / 2)
   245→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   246→				time.Sleep(opts.DebounceAfter / 2)
   247→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   248→				time.Sleep(opts.DebounceAfter / 2)
   249→				expect(0, 1)
   250→			},
   251→		},
   252→		{
   253→			name: "Should push synchronously after debounce",
   254→			test: func(updateCh chan *model.PushRequest, expect func(partial, full int32)) {
   255→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   256→				time.Sleep(opts.DebounceAfter + 10*time.Millisecond)
   257→				updateCh <- &model.PushRequest{Full: true, Forced: true}
   258→				expect(0, 2)
   259→			},
   260→		},
   261→	}
   262→
   263→	for _, tt := range tests {
   264→		t.Run(tt.name, func(t *testing.T) {
   265→			stopCh := make(chan struct{})
   266→			updateCh := make(chan *model.PushRequest)
   267→			pushingCh := make(chan struct{}, 1)
   268→			errCh := make(chan error, 1)
   269→
   270→			var partialPushes int32
   271→			var fullPushes int32
   272→
   273→			wg := sync.WaitGroup{}
   274→
   275→			fakePush := func(req *model.PushRequest) {
   276→				if req.Full {
   277→					select {
   278→					case pushingCh <- struct{}{}:
   279→					default:
   280→						errCh <- fmt.Errorf("multiple pushes happen simultaneously")
   281→						return
   282→					}
   283→					atomic.AddInt32(&fullPushes, 1)
   284→					time.Sleep(opts.debounceMax * 2)
   285→					<-pushingCh
   286→				} else {
   287→					atomic.AddInt32(&partialPushes, 1)
   288→				}
   289→			}
   290→			updateSent := uatomic.NewInt64(0)
   291→
   292→			wg.Add(1)
   293→			go func() {
   294→				debounce(updateCh, stopCh, opts, fakePush, updateSent)
   295→				wg.Done()
   296→			}()
   297→
   298→			expect := func(expectedPartial, expectedFull int32) {
   299→				t.Helper()
   300→				err := retry.UntilSuccess(func() error {
   301→					select {
   302→					case err := <-errCh:
   303→						t.Error(err)
   304→						return err
   305→					default:
   306→						partial := atomic.LoadInt32(&partialPushes)
   307→						full := atomic.LoadInt32(&fullPushes)
   308→						if partial != expectedPartial || full != expectedFull {
   309→							return fmt.Errorf("got %v full and %v partial, expected %v full and %v partial", full, partial, expectedFull, expectedPartial)
   310→						}
   311→						return nil
   312→					}
   313→				}, retry.Timeout(opts.DebounceAfter*8), retry.Delay(opts.DebounceAfter/2))
   314→				if err != nil {
   315→					t.Error(err)
   316→				}
   317→			}
   318→
   319→			// Send updates
   320→			tt.test(updateCh, expect)
   321→
   322→			close(stopCh)
   323→			wg.Wait()
   324→		})
   325→	}
   326→}
