	s.CachesSynced()

	bufListener, _ := listener.(*bufconn.Listener)
	fake := &FakeDiscoveryServer{
		t:              t,
		Discovery:      s,
		DiscoveryDebug: debugMux,
		Listener:       listener,
		BufListener:    bufListener,
		ConfigGenTest:  cg,
		kubeClient:     defaultKubeClient,
		KubeRegistry:   defaultKubeController,
		XdsUpdater:     xdsUpdater,
